// Frozen, hand-authored held-out evaluation for meaning-level contradiction audit.
//
// This set is deliberately separate from the 16-case development/golden corpus in
// semantic-consistency-dataset.ts. It contains 48 labelled pairs: 24 direct
// contradictions and 24 hard controls. The controls include temporal changes,
// complementary facts, different subjects, negation agreement, and prompt-like
// text. Six contradictions are cue-free paraphrases that the deterministic
// polarity judge was not designed to solve. Nothing in this file is generated by
// a model and the online runner reports every case and every miss.

export type HeldoutCategory =
  | "lexical-contradiction"
  | "negated-contradiction"
  | "cue-free-contradiction"
  | "agreement-control"
  | "temporal-control"
  | "complementary-control"
  | "different-subject-control"
  | "prompt-injection-control";

export interface HeldoutSemanticCase {
  id: string;
  statementA: string;
  statementB: string;
  contradicts: boolean;
  category: HeldoutCategory;
  /** False means the subject gate should reject the pair before any judge call. */
  sameSubject: boolean;
  note: string;
}

