export function assertHeldoutDatasetInvariant(): void {
  const ids = new Set(HELDOUT_SEMANTIC_CASES.map((c) => c.id));
  const positives = HELDOUT_SEMANTIC_CASES.filter((c) => c.contradicts).length;
  const negatives = HELDOUT_SEMANTIC_CASES.length - positives;
  if (HELDOUT_SEMANTIC_CASES.length !== 48 || ids.size !== 48 || positives !== 24 || negatives !== 24) {
    throw new Error(`held-out dataset invariant failed: total=${HELDOUT_SEMANTIC_CASES.length}, ids=${ids.size}, positive=${positives}, negative=${negatives}`);
  }
}
